     1→"use client";
     2→
     3→import useSWR from "swr";
     4→import Link from "next/link";
     5→import {
     6→  semanticReleases as srApi,
     7→  projects as projectsApi,
     8→  sources as sourcesApi,
     9→  contextSources,
    10→} from "@/lib/api/client";
    11→import { useRouter } from "next/navigation";
    12→import { StatusDot } from "@/components/ui/status-dot";
    13→import { VersionChip } from "@/components/ui/version-chip";
    14→import { SectionLabel } from "@/components/ui/section-label";
    15→import { ProviderBadge } from "@/components/ui/provider-badge";
    16→import { timeAgo } from "@/lib/format";
    17→import { getPathSegment } from "@/lib/path";
    18→import {
    19→  ArrowLeft,
    20→  Check,
    21→  ExternalLink,
    22→  Copy,
    23→  ShieldAlert,
    24→  BookOpen,
    25→  Download,
    26→} from "lucide-react";
    27→
    28→function getRiskColors(riskLevel?: string) {
    29→  switch (riskLevel?.toUpperCase()) {
    30→    case "CRITICAL":
    31→      return { border: "#dc2626", bg: "#fff1f2", text: "#991b1b" };
    32→    case "HIGH":
    33→      return { border: "#d97706", bg: "#fff8f0", text: "#92400e" };
    34→    case "MEDIUM":
    35→      return { border: "#ca8a04", bg: "#fefce8", text: "#854d0e" };
    36→    case "LOW":
    37→    default:
    38→      return { border: "#16a34a", bg: "#f0fdf4", text: "#166534" };
    39→  }
    40→}
    41→
    42→function safeHostname(url: string): string {
    43→  try {
    44→    return new URL(url).hostname.replace("www.", "");
    45→  } catch {
    46→    return url;
    47→  }
    48→}
    49→
    50→function getDownloadLabel(url: string): { label: string; isDirect: boolean } {
    51→  const lower = url.toLowerCase();
    52→  const filename = lower.split("/").pop() ?? "";
    53→
    54→  // Detect platform from common patterns in the URL or filename
    55→  const platforms: [RegExp, string][] = [
    56→    [/linux.*amd64|amd64.*linux/, "Linux x64"],
    57→    [/linux.*arm64|arm64.*linux|linux.*aarch64/, "Linux ARM64"],
    58→    [/linux.*386|linux.*i386/, "Linux x86"],
    59→    [/darwin.*arm64|arm64.*darwin|macos.*arm64|osx.*arm64/, "macOS ARM64"],
    60→    [/darwin.*amd64|amd64.*darwin|macos.*amd64|osx.*amd64/, "macOS x64"],
    61→    [/darwin|macos|osx/, "macOS"],
    62→    [/windows.*amd64|amd64.*windows|win64/, "Windows x64"],
    63→    [/windows.*386|win32/, "Windows x86"],
    64→    [/windows/, "Windows"],
    65→  ];
    66→
    67→  // Check if this is a direct binary (archive or executable)
    68→  const isArchive = /\.(tar\.gz|tar\.xz|zip|deb|rpm|dmg|msi|exe|pkg|appimage)(\?|$)/i.test(url);
    69→
    70→  if (isArchive) {
    71→    for (const [pattern, label] of platforms) {
    72→      if (pattern.test(filename) || pattern.test(url)) {
    73→        return { label, isDirect: true };
    74→      }
    75→    }
    76→    // Direct download but platform unknown — use filename
    77→    const cleanName = (url.split("/").pop() ?? "").split("?")[0];
    78→    return { label: cleanName || safeHostname(url), isDirect: true };
    79→  }
    80→
    81→  // Not a direct binary — generic link
    82→  return { label: safeHostname(url), isDirect: false };
    83→}
    84→
    85→export function SemanticReleaseDetail() {
    86→  // Read IDs from URL path — useParams() returns stale "0" in static export
    87→  const projectId = getPathSegment(1); // /projects/{id}/semantic-releases/{srId}
    88→  const srId = getPathSegment(3);
    89→  const router = useRouter();
    90→  const { data, isLoading } = useSWR(`sr-${srId}`, () => srApi.get(srId));
    91→  const { data: projectData } = useSWR(`project-${projectId}`, () =>
    92→    projectsApi.get(projectId),
    93→  );
    94→  const { data: srSourcesData } = useSWR(`sr-sources-${srId}`, () =>
    95→    srApi.getSources(srId),
    96→  );
    97→  const { data: sourcesData } = useSWR(`project-sources-${projectId}`, () =>
    98→    sourcesApi.listByProject(projectId),
    99→  );
   100→  const { data: contextSourcesData } = useSWR(
   101→    `project-context-sources-${projectId}`,
   102→    () => contextSources.list(projectId),
   103→  );
   104→
   105→  if (isLoading) {
   106→    return (
   107→      <div className="flex justify-center py-20">
   108→        <div
   109→          className="text-[13px] text-[#9ca3af]"
   110→          style={{ fontFamily: "var(--font-dm-sans)" }}
   111→        >
   112→          Loading...
   113→        </div>
   114→      </div>
   115→    );
   116→  }
   117→
   118→  const sr = data?.data;
   119→  if (!sr) {
   120→    return (
   121→      <div className="flex justify-center py-20">
   122→        <div
   123→          className="text-[13px] text-[#9ca3af]"
   124→          style={{ fontFamily: "var(--font-dm-sans)" }}
   125→        >
   126→          Semantic release not found
   127→        </div>
   128→      </div>
   129→    );
   130→  }
   131→
   132→  const project = projectData?.data;
   133→  const releasesList = srSourcesData?.data ?? [];
   134→  const sourcesList = sourcesData?.data ?? [];
   135→  const sourcesById = Object.fromEntries(sourcesList.map((s) => [s.id, s]));
   136→  const contextSourcesList = contextSourcesData?.data ?? [];
   137→
   138→  const handleDelete = async () => {
   139→    if (!confirm("Delete this semantic release?")) return;
   140→    try {
   141→      await srApi.delete(srId);
   142→      router.push("/releases");
   143→    } catch {
   144→      alert("Failed to delete semantic release.");
   145→    }
   146→  };
   147→
   148→  const report = sr.report;
   149→  const riskLevel = (report?.urgency ?? report?.risk_level)?.toUpperCase();
   150→  const hasRiskOrUrgency = riskLevel || report?.urgency;
   151→  const riskColors = getRiskColors(riskLevel);
   152→
   153→  const statusChecks = report?.status_checks ?? [];
   154→  const downloadLinks = report?.download_links ?? [];
   155→  const downloadCommands = report?.download_commands ?? [];
   156→  const hasAvailabilitySection =
   157→    statusChecks.length > 0 ||
   158→    downloadLinks.length > 0 ||
   159→    downloadCommands.length > 0;
   160→
   161→  return (
   162→    <div className="fade-in mx-auto max-w-[760px]">
   163→      {/* 1. Back link */}
   164→      <Link
   165→        href="/releases"
   166→        className="mb-6 inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   167→        style={{
   168→          fontFamily: "var(--font-dm-sans)",
   169→          fontSize: "13px",
   170→          color: "#6b7280",
   171→        }}
   172→      >
   173→        <ArrowLeft size={14} />
   174→        Back to Releases
   175→      </Link>
   176→
   177→      {/* 2. Project byline */}
   178→      {project?.name && (
   179→        <p
   180→          className="mb-1 text-[13px] italic text-[#9ca3af]"
   181→          style={{ fontFamily: "var(--font-fraunces)" }}
   182→        >
   183→          {project.name}
   184→        </p>
   185→      )}
   186→
   187→      {/* 3. Version heading */}
   188→      <h1
   189→        className="text-[42px] font-bold tracking-tight text-[#111113] leading-[1.1]"
   190→        style={{ fontFamily: "var(--font-fraunces)" }}
   191→      >
   192→        {sr.version}
   193→      </h1>
   194→
   195→      {/* 4. Subject line */}
   196→      {report?.subject && (
   197→        <p
   198→          className="mt-2 text-[20px] leading-[1.4] text-[#374151]"
   199→          style={{ fontFamily: "var(--font-dm-sans)" }}
   200→        >
   201→          {report.subject}
   202→        </p>
   203→      )}
   204→
   205→      {/* 5. Meta line */}
   206→      <div
   207→        className="mt-3 flex items-center gap-2 text-[13px] text-[#6b7280]"
   208→        style={{ fontFamily: "var(--font-dm-sans)" }}
   209→      >
   210→        <StatusDot status={sr.status} />
   211→        <span className="flex-1">
   212→          {sr.status}
   213→          {sr.completed_at && ` \u00b7 generated ${timeAgo(sr.completed_at)}`}
   214→        </span>
   215→        <button
   216→          onClick={handleDelete}
   217→          className="rounded-md px-2.5 py-1 text-[12px] font-medium text-[#991b1b] transition-colors hover:bg-[#fef2f2]"
   218→          style={{ fontFamily: "var(--font-dm-sans)" }}
   219→        >
   220→          Delete
   221→        </button>
   222→      </div>
   223→
   224→      {/* 6. Divider */}
   225→      <hr
   226→        className="my-8 border-0"
   227→        style={{ borderTop: "1px solid #e8e8e5" }}
   228→      />
   229→
   230→      {/* 7. Error state */}
   231→      {sr.error && (
   232→        <div
   233→          className="mb-8 rounded-md px-4 py-3 text-[14px] text-[#991b1b]"
   234→          style={{
   235→            border: "1px solid #fca5a5",
   236→            backgroundColor: "#fef2f2",
   237→            fontFamily: "var(--font-dm-sans)",
   238→          }}
   239→        >
   240→          {sr.error}
   241→        </div>
   242→      )}
   243→
   244→      {report && (
   245→        <div className="space-y-10">
   246→          {/* 8. Risk & Urgency Banner */}
   247→          {hasRiskOrUrgency && (
   248→            <div
   249→              className="rounded-md px-4 py-4"
   250→              style={{
   251→                backgroundColor: riskColors.bg,
   252→                borderLeft: `3px solid ${riskColors.border}`,
   253→              }}
   254→            >
   255→              <div className="flex items-start gap-3">
   256→                <ShieldAlert
   257→                  className="h-5 w-5 mt-0.5 shrink-0"
   258→                  style={{ color: riskColors.border }}
   259→                />
   260→                <div className="flex-1">
   261→                  <div className="flex items-center gap-2 mb-1">
   262→                    {riskLevel && (
   263→                      <span
   264→                        className="rounded px-1.5 py-0.5 text-[11px] font-bold uppercase"
   265→                        style={{
   266→                          backgroundColor: riskColors.border,
   267→                          color: "#ffffff",
   268→                        }}
   269→                      >
   270→                        {riskLevel} URGENCY
   271→                      </span>
   272→                    )}
   273→                  </div>
   274→                  {(report.urgency_reason ?? report.risk_reason) && (
   275→                    <p
   276→                      className="text-[14px] leading-[1.6]"
   277→                      style={{
   278→                        color: riskColors.text,
   279→                        fontFamily: "var(--font-dm-sans)",
   280→                      }}
   281→                    >
   282→                      {report.urgency_reason ?? report.risk_reason}
   283→                    </p>
   284→                  )}
   285→                </div>
   286→              </div>
   287→            </div>
   288→          )}
   289→
   290→          {/* 9. Status Checks & Downloads */}
   291→          {hasAvailabilitySection && (
   292→            <section>
   293→              <SectionLabel className="mb-3">
   294→                Availability & Downloads
   295→              </SectionLabel>
   296→
   297→              {/* Status checks as green pills */}
   298→              {statusChecks.length > 0 && (
   299→                <div className="flex flex-wrap gap-2 mb-4">
   300→                  {statusChecks.map((check) => (
   301→                    <span
   302→                      key={check}
   303→                      className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium"
   304→                      style={{
   305→                        backgroundColor: "#f0fdf4",
   306→                        color: "#166534",
   307→                        border: "1px solid #bbf7d0",
   308→                        fontFamily: "var(--font-dm-sans)",
   309→                      }}
   310→                    >
   311→                      <Check size={14} />
   312→                      {check}
   313→                    </span>
   314→                  ))}
   315→                </div>
   316→              )}
   317→
   318→              {/* Download links — platform binaries + generic links */}
   319→              {downloadLinks.length > 0 && (
   320→                <div className="flex flex-wrap gap-2 mb-4">
   321→                  {downloadLinks.map((link) => {
   322→                    const { label, isDirect } = getDownloadLabel(link);
   323→                    return isDirect ? (
   324→                      <a
   325→                        key={link}
   326→                        href={link}
   327→                        target="_blank"
   328→                        rel="noopener noreferrer"
   329→                        className="inline-flex items-center gap-1.5 rounded-md px-3 py-1.5 text-[13px] font-medium transition-colors hover:opacity-80"
   330→                        style={{
   331→                          backgroundColor: "#111113",
   332→                          color: "#ffffff",
   333→                          fontFamily: "var(--font-dm-sans)",
   334→                        }}
   335→                      >
   336→                        <Download size={13} />
   337→                        {label}
   338→                      </a>
   339→                    ) : (
   340→                      <a
   341→                        key={link}
   342→                        href={link}
   343→                        target="_blank"
   344→                        rel="noopener noreferrer"
   345→                        className="inline-flex items-center gap-1.5 rounded-full px-3 py-1 text-[13px] font-medium transition-colors hover:opacity-80"
   346→                        style={{
   347→                          backgroundColor: "#f3f3f1",
   348→                          color: "#374151",
   349→                          border: "1px solid #e8e8e5",
   350→                          fontFamily: "var(--font-dm-sans)",
   351→                        }}
   352→                      >
   353→                        <ExternalLink size={12} />
   354→                        {label}
   355→                      </a>
   356→                    );
   357→                  })}
   358→                </div>
   359→              )}
   360→
   361→              {/* Download commands as copiable code */}
   362→              {downloadCommands.length > 0 && (
   363→                <div className="space-y-2">
   364→                  {downloadCommands.map((cmd) => (
   365→                    <div
   366→                      key={cmd}
   367→                      className="group flex items-center gap-2 rounded-md px-3 py-2"
   368→                      style={{
   369→                        backgroundColor: "#fafaf9",
   370→                        border: "1px solid #e8e8e5",
   371→                      }}
   372→                    >
   373→                      <code
   374→                        className="flex-1 text-[13px] text-[#111113]"
   375→                        style={{ fontFamily: "'JetBrains Mono', monospace" }}
   376→                      >
   377→                        {cmd}
   378→                      </code>
   379→                      <button
   380→                        onClick={() => navigator.clipboard.writeText(cmd)}
   381→                        className="shrink-0 rounded p-1 text-[#9ca3af] opacity-0 transition-opacity group-hover:opacity-100 hover:text-[#374151]"
   382→                        title="Copy"
   383→                      >
   384→                        <Copy size={14} />
   385→                      </button>
   386→                    </div>
   387→                  ))}
   388→                </div>
   389→              )}
   390→            </section>
   391→          )}
   392→
   393→          {/* 10. Adoption */}
   394→          {report.adoption && (
   395→            <section>
   396→              <SectionLabel className="mb-2">Adoption</SectionLabel>
   397→              <div
   398→                className="rounded-md p-4"
   399→                style={{
   400→                  border: "1px solid #e8e8e5",
   401→                  backgroundColor: "#ffffff",
   402→                }}
   403→              >
   404→                <p
   405→                  className="text-[14px] leading-[1.6] text-[#111113]"
   406→                  style={{ fontFamily: "var(--font-dm-sans)" }}
   407→                >
   408→                  {report.adoption}
   409→                </p>
   410→              </div>
   411→            </section>
   412→          )}
   413→
   414→          {/* 11. Source Releases */}
   415→          {releasesList.length > 0 && (
   416→            <section>
   417→              <SectionLabel className="mb-4">Source Releases</SectionLabel>
   418→              <div
   419→                className="overflow-hidden rounded-md"
   420→                style={{ border: "1px solid #e8e8e5" }}
   421→              >
   422→                <table className="w-full text-left">
   423→                  <thead>
   424→                    <tr
   425→                      style={{
   426→                        backgroundColor: "#fafaf9",
   427→                        borderBottom: "1px solid #e8e8e5",
   428→                      }}
   429→                    >
   430→                      <th
   431→                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   432→                        style={{ fontFamily: "var(--font-dm-sans)" }}
   433→                      >
   434→                        Provider
   435→                      </th>
   436→                      <th
   437→                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   438→                        style={{ fontFamily: "var(--font-dm-sans)" }}
   439→                      >
   440→                        Repository
   441→                      </th>
   442→                      <th
   443→                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   444→                        style={{ fontFamily: "var(--font-dm-sans)" }}
   445→                      >
   446→                        Version
   447→                      </th>
   448→                      <th
   449→                        className="px-4 py-2.5 text-[11px] font-medium uppercase tracking-[0.08em] text-[#9ca3af]"
   450→                        style={{ fontFamily: "var(--font-dm-sans)" }}
   451→                      >
   452→                        Date
   453→                      </th>
   454→                    </tr>
   455→                  </thead>
   456→                  <tbody>
   457→                    {releasesList.map((rel) => {
   458→                      const source = sourcesById[rel.source_id];
   459→                      const versionUrl =
   460→                        source?.provider === "github"
   461→                          ? `https://github.com/${source.repository}/releases/tag/${rel.version}`
   462→                          : source?.provider === "dockerhub"
   463→                            ? `https://hub.docker.com/r/${source.repository}/tags?name=${encodeURIComponent(rel.version)}`
   464→                            : source?.provider === "ecr-public"
   465→                              ? `https://gallery.ecr.aws/${source.repository}`
   466→                              : null;
   467→
   468→                      return (
   469→                        <tr
   470→                          key={rel.id}
   471→                          className="border-b border-[#e8e8e5] last:border-b-0"
   472→                        >
   473→                          <td className="px-4 py-3">
   474→                            {source ? (
   475→                              <ProviderBadge provider={source.provider} />
   476→                            ) : (
   477→                              <span className="text-[12px] text-[#9ca3af]">
   478→                                {"\u2014"}
   479→                              </span>
   480→                            )}
   481→                          </td>
   482→                          <td className="px-4 py-3">
   483→                            <span
   484→                              className="text-[13px] text-[#374151]"
   485→                              style={{
   486→                                fontFamily: "'JetBrains Mono', monospace",
   487→                              }}
   488→                            >
   489→                              {source?.repository ?? "\u2014"}
   490→                            </span>
   491→                          </td>
   492→                          <td className="px-4 py-3">
   493→                            {versionUrl ? (
   494→                              <a
   495→                                href={versionUrl}
   496→                                target="_blank"
   497→                                rel="noopener noreferrer"
   498→                                className="inline-flex items-center gap-1 hover:opacity-70 transition-opacity"
   499→                              >
   500→                                <VersionChip version={rel.version} />
   501→                                <ExternalLink
   502→                                  size={11}
   503→                                  className="text-[#9ca3af]"
   504→                                />
   505→                              </a>
   506→                            ) : (
   507→                              <VersionChip version={rel.version} />
   508→                            )}
   509→                          </td>
   510→                          <td className="px-4 py-3">
   511→                            <span
   512→                              className="text-[13px] text-[#6b7280]"
   513→                              style={{ fontFamily: "var(--font-dm-sans)" }}
   514→                            >
   515→                              {timeAgo(rel.released_at ?? rel.created_at)}
   516→                            </span>
   517→                          </td>
   518→                        </tr>
   519→                      );
   520→                    })}
   521→                  </tbody>
   522→                </table>
   523→              </div>
   524→            </section>
   525→          )}
   526→
   527→          {/* 12. Context Sources */}
   528→          {contextSourcesList.length > 0 && (
   529→            <section>
   530→              <SectionLabel className="mb-3">Context Sources</SectionLabel>
   531→              <div className="space-y-2">
   532→                {contextSourcesList.map((cs) => {
   533→                  const url = cs.config?.url as string | undefined;
   534→                  return (
   535→                    <div
   536→                      key={cs.id}
   537→                      className="flex items-center gap-3 rounded-md px-4 py-3"
   538→                      style={{
   539→                        border: "1px solid #e8e8e5",
   540→                        backgroundColor: "#ffffff",
   541→                      }}
   542→                    >
   543→                      <BookOpen
   544→                        size={16}
   545→                        className="shrink-0 text-[#9ca3af]"
   546→                      />
   547→                      <div className="flex-1 min-w-0">
   548→                        <span
   549→                          className="text-[14px] font-medium text-[#111113]"
   550→                          style={{ fontFamily: "var(--font-dm-sans)" }}
   551→                        >
   552→                          {cs.name}
   553→                        </span>
   554→                        <span
   555→                          className="ml-2 rounded px-1.5 py-0.5 text-[11px] font-medium uppercase text-[#6b7280]"
   556→                          style={{ backgroundColor: "#f3f3f1" }}
   557→                        >
   558→                          {cs.type}
   559→                        </span>
   560→                      </div>
   561→                      {url && (
   562→                        <a
   563→                          href={url}
   564→                          target="_blank"
   565→                          rel="noopener noreferrer"
   566→                          className="shrink-0 text-[#9ca3af] hover:text-[#374151] transition-colors"
   567→                        >
   568→                          <ExternalLink size={14} />
   569→                        </a>
   570→                      )}
   571→                    </div>
   572→                  );
   573→                })}
   574→              </div>
   575→            </section>
   576→          )}
   577→
   578→          {/* 13. Changelog Summary */}
   579→          {report.changelog_summary && (
   580→            <section>
   581→              <SectionLabel className="mb-3">Changelog Summary</SectionLabel>
   582→              <p
   583→                className="text-[16px] leading-[1.7] text-[#111113]"
   584→                style={{ fontFamily: "var(--font-dm-sans)" }}
   585→              >
   586→                {report.changelog_summary}
   587→              </p>
   588→            </section>
   589→          )}
   590→
   591→
   592→        </div>
   593→      )}
   594→    </div>
   595→  );
   596→}
   597→

<system-reminder>
Whenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.
</system-reminder>

