    24→
    25→/** Returns true if the string already contains HTML tags. */
    26→function looksLikeHtml(s: string): boolean {
    27→  return /<[a-z][\s\S]*>/i.test(s);
    28→}
    29→
    30→/** Convert changelog to HTML — pass through if already HTML, otherwise render as markdown. */
    31→function changelogToHtml(raw: string): string {
    32→  if (looksLikeHtml(raw)) return raw;
    33→  return marked.parse(raw, { async: false }) as string;
    34→}
    35→
    36→function getProviderUrl(
    37→  provider: string,
    38→  repository: string,
    39→  version: string
    40→): string | null {
    41→  switch (provider) {
    42→    case "github":
    43→      return `https://github.com/${repository}/releases/tag/${version}`;
    44→    case "dockerhub":
    45→      return `https://hub.docker.com/r/${repository}/tags?name=${encodeURIComponent(version)}`;
    46→    case "ecr-public":
    47→      return `https://gallery.ecr.aws/${repository}`;
    48→    case "gitlab":
    49→      return `https://gitlab.com/${repository}/-/releases/${version}`;
    50→    default:
    51→      return null;
    52→  }
    53→}
    54→
    55→function getProviderLabel(provider: string): string {
    56→  switch (provider) {
    57→    case "github":
    58→      return "GitHub";
    59→    case "dockerhub":
    60→      return "Docker Hub";
    61→    case "ecr-public":
    62→      return "ECR Public";
    63→    case "gitlab":
    64→      return "GitLab";
    65→    default:
    66→      return provider;
    67→  }
    68→}
