   154→      {/* Back link */}
   155→      <Link
   156→        href="/releases"
   157→        className="inline-flex items-center gap-1.5 transition-colors hover:opacity-70"
   158→        style={{
   159→          fontFamily: "var(--font-dm-sans)",
   160→          fontSize: "13px",
   161→          color: "#6b7280",
