   418→                fontSize: "14px",
   419→                color: "#9ca3af",
   420→              }}
   421→            >
   422→              No release notes available
   423→            </p>
   424→          )}
   425→        </div>
   426→      </div>
   427→    </div>
   428→  );
   429→}
