   434→
   435→function DetailRow({
   436→  label,
   437→  value,
   438→  mono,
   439→  small,
   440→}: {
   441→  label: string;
   442→  value: string;
   443→  mono?: boolean;
   444→  small?: boolean;
   445→}) {
   446→  return (
   447→    <div className="flex items-baseline justify-between gap-4">
   448→      <span
   449→        style={{
   450→          fontFamily: "var(--font-dm-sans)",
   451→          fontSize: "13px",
   452→          color: "#9ca3af",
   453→        }}
   454→      >
   455→        {label}
   456→      </span>
   457→      <span
   458→        className="text-right"
   459→        style={{
   460→          fontFamily: mono ? "'JetBrains Mono', monospace" : "var(--font-dm-sans)",
   461→          fontSize: small ? "11px" : "13px",
   462→          color: "#374151",
   463→        }}
   464→      >
   465→        {value}
   466→      </span>
   467→    </div>
   468→  );
   469→}
